DIM    = [0,31,28,31,30,31,30,31,31,30,31,30,31]
EMOJI  = {"A":"☀️","B":"☁️","C":"🌧️"}
WX     = {"A":"맑음","B":"흐림","C":"비"}
MONTHS = ["","1월","2월","3월","4월","5월","6월","7월","8월","9월","10월","11월","12월"]
DAYS   = ["월","화","수","목","금","토","일"]
BG     = {"A":"#FFF9C4","B":"#BBDEFB","C":"#C8E6C9"}
TC     = {"A":"#7B5800","B":"#0D47A1","C":"#1B5E20"}


def annual_stats():
    ok = sum(1 for r in WEATHER_DATA if r["ok"])
    n  = len(WEATHER_DATA)
    return dict(
        acc=round(ok/n*100), ok=ok, miss=n-ok,
        fcA=sum(1 for r in WEATHER_DATA if r["fc"]=="A"),
        fcB=sum(1 for r in WEATHER_DATA if r["fc"]=="B"),
        fcC=sum(1 for r in WEATHER_DATA if r["fc"]=="C"),
        acA=sum(1 for r in WEATHER_DATA if r["act"]=="A"),
        acB=sum(1 for r in WEATHER_DATA if r["act"]=="B"),
        acC=sum(1 for r in WEATHER_DATA if r["act"]=="C"),
        mm=round(sum(r["mm"] for r in WEATHER_DATA),1),
    )

def month_stats(m):
    md = [r for r in WEATHER_DATA if r["m"]==m]
    ok = sum(1 for r in md if r["ok"])
    n  = len(md)
    return dict(
        ok=ok, miss=n-ok, acc=round(ok/n*100) if n else 0,
        mm=round(sum(r["mm"] for r in md),1),
        fcA=sum(1 for r in md if r["fc"]=="A"),
        fcB=sum(1 for r in md if r["fc"]=="B"),
        fcC=sum(1 for r in md if r["fc"]=="C"),
        acA=sum(1 for r in md if r["act"]=="A"),
        acB=sum(1 for r in md if r["act"]=="B"),
        acC=sum(1 for r in md if r["act"]=="C"),
    )

def build_weeks(m):
    by_day = {r["d"]:r for r in WEATHER_DATA if r["m"]==m}
    first  = date(2025,m,1).weekday()
    cells  = [None]*first + list(range(1, DIM[m]+1))
    while len(cells)%7: cells.append(None)
    return [{7:i for i in range(7)} and
            [cells[w*7+i] for i in range(7)]
            for w in range(len(cells)//7)], by_day

def day_html(day, r, dow, cur_f):
    faded   = (cur_f=="일치만" and not r["ok"]) or (cur_f=="불일치만" and r["ok"])
    op      = "0.18" if faded else "1"
    bg      = "#DCEDC8" if r["ok"] else "#FFCDD2"
    bd_col  = "#7CB342" if r["ok"] else "#E57373"
    num_col = "#1565C0" if dow==5 else "#C62828" if dow==6 else "#1F4E79"
    ico     = "✅" if r["ok"] else "❌"
    fb, ft  = BG[r["fc"]],  TC[r["fc"]]
    ab, at  = BG[r["act"]], TC[r["act"]]
    fe, ae  = EMOJI[r["fc"]], EMOJI[r["act"]]
    fw, aw  = WX[r["fc"]],   WX[r["act"]]
    return (
        f'<div style="opacity:{op};border-radius:8px;border:2px solid {bd_col};'
        f'background:#fff;overflow:hidden;display:flex;flex-direction:column;min-height:90px">'
        f'<div style="background:{bg};padding:3px 5px 2px;display:flex;'
        f'justify-content:space-between;align-items:center">'
        f'<span style="font-size:.82rem;font-weight:700;color:{num_col}">{day}</span>'
        f'<span style="font-size:.65rem">{ico}</span></div>'
        f'<div style="flex:1;display:flex;flex-direction:column;justify-content:center;'
        f'gap:2px;padding:3px 5px">'
        f'<div style="display:flex;align-items:center;gap:3px">'
        f'<span style="font-size:.58rem;color:#bbb;width:14px">예)</span>'
        f'<span style="background:{fb};color:{ft};padding:1px 6px;border-radius:3px;'
        f'font-size:.78rem;font-weight:700">{fe} {fw}</span></div>'
        f'<div style="display:flex;align-items:center;gap:3px">'
        f'<span style="font-size:.58rem;color:#bbb;width:14px">실)</span>'
        f'<span style="background:{ab};color:{at};padding:1px 6px;border-radius:3px;'
        f'font-size:.78rem;font-weight:700">{ae} {aw}</span></div></div>'
        f'<div style="font-size:.56rem;color:#bbb;text-align:right;padding:1px 5px 3px">'
        f'{r["prob"]}% · {r["mm"]}mm</div></div>'
    )

def empty_html():
    return '<div style="border-radius:8px;background:#F8F8F8;border:1px solid #ECECEC;min-height:90px"></div>'


